  ('immigration-1aab856d-moex-00424', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於定期失效之違憲法律，下列敘述何者錯誤？', '["一部法律或部分法條未經司法院大法官宣告違憲之前，具有被推定合法有效的效力", "法律因大法官宣告違憲，應定期失效者，人民得據相關釋憲之原因事實，請求再審或其他救濟", "檢察總長不得依釋憲之原因事實，提起非常上訴", "若於尚未失效之過渡期間內仍繼續適用舊法，法理上應受到嚴格限縮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00425', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依司法院大法官解釋，關於信賴保護原則之敘述，下列何者正確？', '["信賴保護原則限於授益行政處分之撤銷或廢止，始有適用", "純屬願望、期待而未有表現信賴之事實者，欠缺信賴保護要件", "經廢止之法規有重大明顯違反上位規範情形者，亦有信賴保護原則之適用", "法規預先定有施行期間，亦生信賴保護之問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00426', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '加值型及非加值型營業稅法第51條規定：「納稅義務人有左列情形之一者，除追繳稅款外，按所 漏稅額處五倍以下罰鍰，並得停止其營業……」，就此規定之適用，下列敘述何者錯誤？', '["關於追繳稅款之規定，為羈束規定，無裁量餘地", "裁處漏稅額5倍以下之罰鍰，稅捐稽徵機關有裁量權", "是否停止營業，稅捐稽徵機關有裁量權", "裁處罰鍰與停止營業僅得擇一為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
