  ('immigration-1aab856d-moex-00429', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '不能依行政機關組織法規或其他行政法規定土地管轄權時，關於行政機關管轄權之敘述，下列何 者錯誤？', '["關於不動產之事件，依不動產所有權人之居所地", "關於企業之經營或其他繼續性事業之事件，依經營企業或從事事業之處所，或應經營或應從事 之處所", "關於自然人者，依其住所地，無住所或住所不明者，依其居所地，無居所或居所不明者，依其 最後所在地", "有急迫情形者，得依事件發生之原因定管轄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
